def _seed_default_loops(apps, schema_editor):
    """Idempotently seed the default loops + prompts in their final fresh-install shape.

    ``get_or_create`` by ``name`` so a re-run (or a fake-applied initial whose
    rows already exist) creates nothing new and never clobbers an operator-edited
    row. A prompt-backed loop's :class:`Prompt` is seeded first so the nullable FK
    resolves under the loop XOR constraint, and carries the loop's real
    description (matching ``teatree.loops.seed``). ``enabled`` is seeded from the
    per-loop ``default_enabled`` mark — on a fresh DB there is no operator
    ``LoopState`` hold, so seeding the sound-default set ON directly is identical
    to the old seed-paused-then-0043-flip.
    """
    Loop = apps.get_model("core", "Loop")
    Prompt = apps.get_model("core", "Prompt")
    # Scope every write to the alias the migration is running against (matches
    # 0004/0005) so a multi-DB / non-default-alias apply — e.g. a restored fleet
    # DB mounted under a different alias — seeds the DB being migrated, not the
    # default connection.
    db_alias = schema_editor.connection.alias
    for name, delay_seconds, daily_at, prompt_body, description, colleague_facing, default_enabled in _DEFAULT_LOOPS:
        prompt = None
        if prompt_body is not None:
            prompt, _ = Prompt.objects.using(db_alias).get_or_create(
                name=name,
                defaults={"body": prompt_body, "description": description},
            )
        defaults = {
            "delay_seconds": delay_seconds,
            "daily_at": daily_at,
            "description": description,
            "enabled": default_enabled,
            "colleague_facing": colleague_facing,
        }
        if prompt is not None:
            defaults["prompt"] = prompt
        else:
            defaults["script"] = f"src/teatree/loops/{name}/loop.py"
        Loop.objects.using(db_alias).get_or_create(name=name, defaults=defaults)


